insert into public.site_content (id, data) values
  (1, $ym${"hero":{"metaRows":[{"jp":"渋谷","en":"Shibuya, Tokyo"},{"jp":"週末 12〜15時","en":"A Socratica node"}],"taglineLead":"A space for makers, dreamers & builders\nto work on their ","taglineEm":"high-effort passion projects","taglineTail":"\ntogether at the same table.","ctaPrimary":"Join next session","ctaSecondary":"What is Yu+Me?","nextEyebrow":"Next gathering"},"next":{"dateLabel":"Sat. Dec 6","dateShort":"Dec 6","timeLabel":"12:00 – 15:00","locationLabel":"Cr/pto Café & Bar, Shibuya","lumaUrl":"https://luma.com/YuMe"},"manifesto":{"eyebrow":"私たちについて · About","headingLine1":"Come make","headingEm":"your thing","headingLine3":"with us.","paragraphs":["Yu+Me is a weekend co-working session in Shibuya, part of [socratica] — a global network of 40+ nodes where students, alumni, artists and tinkerers gather to make stuff together.","We're united by the love of making things, and we want to help you make your thing. Bring a passion project — coding, writing, knitting, music, gardening, anything. We'll work in Pomodoros, demo what we made, eat snacks, and become friends."],"socraticaUrl":"https://socratica.info","emph":"No work allowed. No homework.","emphPink":"Just the stuff you'd do anyway, with people who care.","stats":[{"n":"40+","l":"Socratica nodes worldwide"},{"n":"3h","l":"Per session"},{"n":"¥0","l":"Always free, by RSVP"}]},"how":{"eyebrow":"流れ · How a session works","heading":"3 hours, one table,\neveryone's making.","sub":"Loosely structured. Mostly snacks and Pomodoros.","steps":[{"n":"01","jp":"集合","t":"Arrive & say hi","body":"Doors open 11:50. We start with snacks, intros and ~15 min of small talk. New face? You'll be welcomed by name.","color":"sky"},{"n":"02","jp":"宣言","t":"Declare your project","body":"Everyone gets 30 seconds to say what they're working on today. The smaller and weirder, the better.","color":"peach"},{"n":"03","jp":"集中","t":"Pomodoro work blocks","body":"Two 50-minute focus blocks with a 10-minute break between. Headphones in. Get the thing done.","color":"mint"},{"n":"04","jp":"発表","t":"Demos & celebrate","body":"Show what you made. 3 bullet points or a half-broken prototype — both count. We clap loudly.","color":"pink"}]},"upcoming":{"eyebrow":"次回 · Upcoming sessions","heading":"Pull up a chair.","lumaUrl":"https://luma.com/YuMe"},"demos":{"eyebrow":"発表 · Demos","heading":"What people\nactually made.","sub":"Whether it's 3 bullet points on a Google Doc or a full-blown prototype, every session ends with demos. Here's a slice."},"gallery":{"eyebrow":"記録 · Past sessions","heading":"The receipts.","sub":"Every Saturday for the last 12 weeks.","instagramUrl":"https://www.instagram.com/weareyume_"},"faqHeading":{"eyebrow":"よくある質問 · FAQ","heading":"Things people ask."},"join":{"eyebrow":"RSVP · 申し込み","title":"See you\nSaturday?","lumaUrl":"https://luma.com/YuMe","reminderEmail":"hello@weareyume.com"},"footer":{"tagline":"A Socratica node based in Shibuya, Tokyo.\n週末 · Weekends · 12:00–15:00","findUs":[{"label":"Luma","url":"https://luma.com/YuMe"},{"label":"Instagram @weareyume_","url":"https://www.instagram.com/weareyume_"},{"label":"X / Twitter","url":"https://x.com/yuandmetokyo"},{"label":"hello@weareyume.com","url":"mailto:hello@weareyume.com"}],"socratica":[{"label":"socratica.info","url":"https://socratica.info"},{"label":"Find a node near you","url":"https://socratica.info/map"},{"label":"Host toolbox","url":"https://toolbox.socratica.info"}],"remindCopy":"One email per session. Nothing else.","bottomLeft":"© 2025 Yu+Me · Made with ❤ in 渋谷","bottomRight":"A Socratica node. The spark continues."}}$ym$::jsonb)
insert into public.demos (tag, title, maker, body, color, sort_order) values
  ($ym$Code · Nov 21$ym$, $ym$Anomia Mobile$ym$, $ym$Aiko$ym$, $ym$A real-time word game ported to React Native — built across 4 sessions.$ym$, $ym$sky$ym$, 0),
  ($ym$Art · Nov 07$ym$, $ym$Tokyo Tower Linocut$ym$, $ym$Marcus$ym$, $ym$A 4-block reduction print, hand-pulled. The third block didn't register but it kind of works.$ym$, $ym$peach$ym$, 1),
  ($ym$Hardware · Oct 18$ym$, $ym$Tea timer for one$ym$, $ym$Ren$ym$, $ym$Tiny e-ink device that brews the perfect cup. Currently lives in a 3D-printed box.$ym$, $ym$mint$ym$, 2),
  ($ym$Writing · Oct 04$ym$, $ym$Zine: Notes on commuting$ym$, $ym$Sora$ym$, $ym$12-page riso zine drafted entirely during a single Pomodoro. Drawings included.$ym$, $ym$pink$ym$, 3),
  ($ym$Music · Sep 20$ym$, $ym$Loop pedal lullabies$ym$, $ym$Yuki$ym$, $ym$An EP of four lullabies. Recorded between Pomodoros on a borrowed mic.$ym$, $ym$sky$ym$, 4),
  ($ym$Web · Sep 06$ym$, $ym$Transit map for ghosts$ym$, $ym$Lex$ym$, $ym$An imaginary subway, plotted on top of the real Yamanote line. Updates every Sunday.$ym$, $ym$peach$ym$, 5);
