insert into public.faqs (question, answer, sort_order) values
  ($ym$I'm not technical. Can I still come?$ym$, $ym$Absolutely. We've had poets, knitters, gardeners, ceramicists and one person training for a marathon. The only requirement is that you're working on something you actually care about.$ym$, 0),
  ($ym$What counts as a 'passion project'?$ym$, $ym$Whatever's been nagging at you that you haven't made time for. Could be a novel, an app, a song, a piece of furniture, learning a language. Not allowed: work for your job, homework, or anything someone is paying you to do.$ym$, 1),
  ($ym$Is this in English or Japanese?$ym$, $ym$Both. Me and Claudia (your hosts) are still pretty beginner at Japanese and very much learning ourselves — so don't worry about your level either way. About half our regulars are non-Japanese; bring whoever, in whichever language.$ym$, 2),
  ($ym$Do I need to bring anything?$ym$, $ym$Just whatever you need to work on your project. Laptops, sketchbooks, knitting needles, weird hardware. We provide snacks, coffee and washi tape.$ym$, 3),
  ($ym$How is this different from a normal coworking space?$ym$, $ym$There's no 'work' here. Yu+Me is about the things you do because you want to, not because you have to. Plus: demos, snacks, friends.$ym$, 4);
